import{c as t,Q as a,j as n,m as s}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"How do I create a new instance?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/create-instance.md","filePath":"guide/recipes/admin/create-instance.md","lastUpdated":1778912818000}'),o={name:"guide/recipes/admin/create-instance.md"};function i(r,e,l,c,d,h){return a(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="how-do-i-create-a-new-instance" tabindex="-1">How do I create a new instance? <a class="header-anchor" href="#how-do-i-create-a-new-instance" aria-label="Permalink to &quot;How do I create a new instance?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Infra Ops</strong></p></div><p>An instance is a deployed Exto stack that hosts tenants. Creating one in the Console registers it — the actual stack is stood up out-of-band, and the credentials returned here are what the instance uses to call back to the Console.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Instances</strong> in the Admin Console sidebar.</li><li>Click <strong>New Instance</strong>.</li><li>Fill in: <ul><li><strong>Name</strong> — e.g. <code>us-east-1a</code>.</li><li><strong>API base URL</strong> — the URL the Console will use to reach this instance&#39;s API.</li><li><strong>MongoDB URI</strong> — the connection string for the instance&#39;s database.</li><li><strong>Max tenants</strong> — soft cap used by tenant placement.</li></ul></li><li>Click <strong>Create Instance</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>A credentials modal appears with four values:</p><ul><li><code>CONSOLE_INSTANCE_TOKEN</code></li><li><code>CONSOLE_INSTANCE_ID</code></li><li><code>CONSOLE_BASE_URL</code></li><li><code>MONGODB_URI</code> (echoed for convenience)</li></ul><div class="warning custom-block"><p class="custom-block-title">Copy the token now</p><p>The token is shown <strong>only once</strong>. Save it to your secrets manager or paste it into the instance&#39;s env config before closing the modal. If you lose it, decommission the instance and create a new one.</p></div><p>The instance appears in the table with status <strong>Active</strong> once it makes its first heartbeat.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./create-tenant">How do I create a new tenant?</a></li><li><a href="./update-env-vars">How do I update environment variables on an instance?</a></li><li><a href="./decommission-instance">How do I decommission an instance?</a></li></ul>',12)])])}const m=t(o,[["render",i]]);export{u as __pageData,m as default};
